const lockDocumentNumberAllocator = `-- name: LockDocumentNumberAllocator :one
SELECT next_number
FROM document_number_allocators
WHERE issuer_id = 'verself'
  AND document_year = $1
FOR UPDATE
`

type LockDocumentNumberAllocatorParams struct {
	DocumentYear int32
}

func (q *Queries) LockDocumentNumberAllocator(ctx context.Context, arg LockDocumentNumberAllocatorParams) (int64, error) {
	row := q.db.QueryRow(ctx, lockDocumentNumberAllocator, arg.DocumentYear)
	var next_number int64
	err := row.Scan(&next_number)
	return next_number, err
}

