const supersedeContractPhaseForUpgrade = `-- name: SupersedeContractPhaseForUpgrade :one
UPDATE contract_phases
SET state = 'superseded',
    entitlement_state = CASE WHEN effective_start < $1 THEN 'closed' ELSE 'voided' END,
    effective_end = CASE WHEN effective_start < $1 THEN $1 ELSE NULL END,
    closed_at = $1
WHERE phase_id = $2
  AND contract_id = $3
  AND state IN ('active','grace')
RETURNING effective_start, entitlement_state
`

