const upsertContract = `-- name: UpsertContract :exec
INSERT INTO contracts (
    contract_id, org_id, product_id, display_name, contract_kind, state,
    payment_state, entitlement_state, overage_policy, starts_at
) VALUES (
    $1, $2, $3, $4,
    'self_serve', 'active', 'paid', 'active', 'bill_published_rate', $5
)
ON CONFLICT (contract_id) DO UPDATE
SET state = 'active',
    payment_state = 'paid',
    entitlement_state = 'active',
    display_name = EXCLUDED.display_name,
    ends_at = NULL,
    cancel_at = NULL
`

type UpsertContractParams struct {
	ContractID  string
	OrgID       string
	ProductID   string
	DisplayName string
	StartsAt    pgtype.Timestamptz
}

func (q *Queries) UpsertContract(ctx context.Context, arg UpsertContractParams) error {
	_, err := q.db.Exec(ctx, upsertContract,
		arg.ContractID,
		arg.OrgID,
		arg.ProductID,
		arg.DisplayName,
		arg.StartsAt,
	)
	return err
}

